request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?nesting WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name ?name .
  OPTIONAL { ?pkg vocab:Package_nestingPackage ?nesting }
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS")))
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?nestingName WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name ?name .
  OPTIONAL { 
    ?pkg vocab:Package_nestingPackage ?nesting .
    ?nesting vocab:NamedElement_name ?nestingName .
  }
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("Conceptual")))
}
LIMIT 50
